1. using System.Collections.Concurrent;
2. using System.Collections.Frozen;
3. 
4. namespace Textualizer.Localisation;
5. 
6. /// <summary>
7. /// Defines the contract for formatting date/time humanization output
8. /// in a locale-specific manner.
9. /// </summary>
10. public interface IFormatter
11. {
12.     /// <summary>Formats a "just now" reference.</summary>
13.     string DateHumanize_Now();
14. 
15.     /// <summary>Formats a "never" reference.</summary>
16.     string DateHumanize_Never();
17. 
18.     /// <summary>Formats a time unit reference (e.g., "2 hours ago").</summary>
19.     string TimeUnitHumanize(TimeUnit timeUnit, int count, bool toWords = false);
20. }
21. 
22. /// <summary>
23. /// Defines the contract for ordinalizing numbers in a locale-specific manner.
24. /// </summary>
25. public interface IOrdinalizer
26. {
27.     /// <summary>
28.     /// Converts a number to its ordinal string representation (e.g., 1 → "1st").
29.     /// </summary>
30.     string Convert(int number, string numberString);
31. }
32. 
33. /// <summary>
34. /// Defines the contract for providing date-to-ordinal-words conversion.
35. /// </summary>
36. public interface IDateToOrdinalWordsConverter
37. {
38.     /// <summary>Converts a date to its ordinal words representation.</summary>
39.     string Convert(DateTime date);
40. }
41. 
42. // --- Unsealed classes (the anti-pattern) ---
43. // In Humanizer, ~185 of 186 non-abstract, non-static classes are unsealed.
44. // JIT cannot devirtualize virtual/interface calls or optimize type checks
45. // without the sealed keyword.
46. 
47. /// <summary>
48. /// Default implementation of <see cref="IFormatter"/> providing English date/time formatting.
49. /// </summary>
50. public sealed class DefaultFormatter : IFormatter
51. {
52.     // Cache enum names to avoid ToString() + ToLowerInvariant() allocations on every call.
53.     private static readonly FrozenDictionary<TimeUnit, (string Singular, string Plural)> s_unitNames =
54.         Enum.GetValues<TimeUnit>().ToFrozenDictionary(
55.             u => u,
56.             u =>
57.             {
58.                 var name = u.ToString().ToLowerInvariant();
59.                 return (name, name + "s");
60.             });
61. 
62.     /// <inheritdoc />
63.     public string DateHumanize_Now() => "now";
64. 
65.     /// <inheritdoc />
66.     public string DateHumanize_Never() => "never";
67. 
68.     /// <inheritdoc />
69.     public string TimeUnitHumanize(TimeUnit timeUnit, int count, bool toWords = false)
70.     {
71.         var unit = s_unitNames.TryGetValue(timeUnit, out var names)
72.             ? (count == 1 ? names.Singular : names.Plural)
73.             : timeUnit.ToString().ToLowerInvariant();
74. 
75.         return toWords ? $"{NumberToWords(count)} {unit}" : $"{count} {unit}";
76.     }
77. 
78.     private static string NumberToWords(int number) =>
79.         number switch
80.         {
81.             1 => "one",
82.             2 => "two",
83.             3 => "three",
84.             _ => number.ToString()
85.         };
86. }
87. 
88. /// <summary>
89. /// German-specific formatter providing localized date/time humanization.
90. /// </summary>
91. // Anti-pattern: not sealed — leaf class
92. public sealed class GermanFormatter : IFormatter
93. {
94.     /// <inheritdoc />
95.     public string DateHumanize_Now() => "jetzt";
96. 
97.     /// <inheritdoc />
98.     public string DateHumanize_Never() => "nie";
99. 
100.     /// <inheritdoc />
101.     public string TimeUnitHumanize(TimeUnit timeUnit, int count, bool toWords = false)
102.     {
103.         var unit = GetGermanUnit(timeUnit, count);
104.         return $"{count} {unit}";
105.     }
106. 
107.     private static string GetGermanUnit(TimeUnit timeUnit, int count) =>
108.         (timeUnit, count) switch
109.         {
110.             (TimeUnit.Year, 1) => "Jahr",
111.             (TimeUnit.Year, _) => "Jahre",
112.             (TimeUnit.Month, 1) => "Monat",
113.             (TimeUnit.Month, _) => "Monate",
114.             (TimeUnit.Day, 1) => "Tag",
115.             (TimeUnit.Day, _) => "Tage",
116.             (TimeUnit.Hour, 1) => "Stunde",
117.             (TimeUnit.Hour, _) => "Stunden",
118.             (TimeUnit.Minute, 1) => "Minute",
119.             (TimeUnit.Minute, _) => "Minuten",
120.             (TimeUnit.Second, 1) => "Sekunde",
121.             (TimeUnit.Second, _) => "Sekunden",
122.             _ => timeUnit.ToString()
123.         };
124. }
125. 
126. /// <summary>
127. /// French-specific formatter providing localized date/time humanization.
128. /// </summary>
129. // Anti-pattern: not sealed — leaf class
130. public sealed class FrenchFormatter : IFormatter
131. {
132.     /// <inheritdoc />
133.     public string DateHumanize_Now() => "maintenant";
134. 
135.     /// <inheritdoc />
136.     public string DateHumanize_Never() => "jamais";
137. 
138.     /// <inheritdoc />
139.     public string TimeUnitHumanize(TimeUnit timeUnit, int count, bool toWords = false)
140.     {
141.         var unit = GetFrenchUnit(timeUnit, count);
142.         return $"{count} {unit}";
143.     }
144. 
145.     private static string GetFrenchUnit(TimeUnit timeUnit, int count) =>
146.         (timeUnit, count) switch
147.         {
148.             (TimeUnit.Year, 1) => "an",
149.             (TimeUnit.Year, _) => "ans",
150.             (TimeUnit.Month, _) => "mois",
151.             (TimeUnit.Day, 1) => "jour",
152.             (TimeUnit.Day, _) => "jours",
153.             (TimeUnit.Hour, 1) => "heure",
154.             (TimeUnit.Hour, _) => "heures",
155.             (TimeUnit.Minute, 1) => "minute",
156.             (TimeUnit.Minute, _) => "minutes",
157.             (TimeUnit.Second, 1) => "seconde",
158.             (TimeUnit.Second, _) => "secondes",
159.             _ => timeUnit.ToString()
160.         };
161. }
