 /// </summary>
 public sealed class DefaultFormatter : IFormatter
 {
     // Cache enum names to avoid ToString() + ToLowerInvariant() allocations on every call.
     private static readonly FrozenDictionary<TimeUnit, (string Singular, string Plural)> s_unitNames =
         Enum.GetValues<TimeUnit>().ToFrozenDictionary(
             u => u,
             u =>
             {
                 var name = u.ToString().ToLowerInvariant();
                 return (name, name + "s");
             });

